import { useState, useRef, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import api from "../api/axios";
import "./Auth.css";

export default function OTPVerify() {
  const [otp, setOtp] = useState(["", "", "", "", "", ""]);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [resendTimer, setResendTimer] = useState(60);
  const [resending, setResending] = useState(false);
  const inputRefs = useRef([]);
  const navigate = useNavigate();
  const location = useLocation();
  const { login: setAuth } = useAuth();

  // รับ email และ type จาก state ที่ส่งมาจากหน้า Login/Register
  const { email, type } = location.state || {};

  useEffect(() => {
    if (!email) navigate("/login");
    inputRefs.current[0]?.focus();
  }, []);

  // countdown timer สำหรับ resend
  useEffect(() => {
    if (resendTimer <= 0) return;
    const timer = setInterval(() => setResendTimer((t) => t - 1), 1000);
    return () => clearInterval(timer);
  }, [resendTimer]);

  const handleChange = (index, value) => {
    if (!/^\d*$/.test(value)) return; // รับแค่ตัวเลข
    const newOtp = [...otp];
    newOtp[index] = value.slice(-1);
    setOtp(newOtp);
    // ขยับไปช่องถัดไปอัตโนมัติ
    if (value && index < 5) inputRefs.current[index + 1]?.focus();
  };

  const handleKeyDown = (index, e) => {
    if (e.key === "Backspace" && !otp[index] && index > 0) {
      inputRefs.current[index - 1]?.focus();
    }
  };

  const handlePaste = (e) => {
    const paste = e.clipboardData.getData("text").replace(/\D/g, "").slice(0, 6);
    if (paste.length === 6) {
      setOtp(paste.split(""));
      inputRefs.current[5]?.focus();
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const code = otp.join("");
    if (code.length !== 6) return setError("Please enter all 6 digits");

    setError("");
    setLoading(true);

    try {
      if (type === "verify") {
        // verify email OTP
        await api.post("/auth/verify-otp", { email, code });
        navigate("/login", { state: { message: "Email verified! You can now login." } });
      } else {
        // 2FA OTP → ได้ JWT
        const res = await api.post("/auth/verify-2fa", { email, code });
        const { accessToken, user } = res.data.data;
        localStorage.setItem("accessToken", accessToken);
        // อัปเดต user ใน context
        window.location.href = user.role === "ADMIN" ? "/admin" : "/dashboard";
      }
    } catch (err) {
      setError(err.response?.data?.message || "Invalid OTP");
      setOtp(["", "", "", "", "", ""]);
      inputRefs.current[0]?.focus();
    } finally {
      setLoading(false);
    }
  };

  const handleResend = async () => {
    setResending(true);
    try {
      await api.post("/auth/resend-otp", { email, type });
      setResendTimer(60);
      setError("");
    } catch (err) {
      setError("Failed to resend OTP");
    } finally {
      setResending(false);
    }
  };

  const title = type === "verify" ? "Verify your email" : "Two-Factor Authentication";
  const desc = type === "verify"
    ? "Enter the 6-digit code sent to your email"
    : "Enter the 6-digit code to complete login";

  return (
    <div className="auth-container">
      <div className="auth-bg">
        <div className="auth-orb orb1" />
        <div className="auth-orb orb2" />
        <div className="auth-orb orb3" />
      </div>

      <div className="auth-card">
        <div className="auth-header">
          <div className="auth-logo">
            <span>⬡</span>
          </div>
          <h1>{title}</h1>
          <p>{desc}</p>
          <p style={{ color: "#4f6ef7", fontSize: "13px", marginTop: "6px" }}>{email}</p>
        </div>

        {error && <div className="auth-error">{error}</div>}

        <form onSubmit={handleSubmit} className="auth-form">
          {/* OTP Input Boxes */}
          <div className="otp-inputs" onPaste={handlePaste}>
            {otp.map((digit, i) => (
              <input
                key={i}
                ref={(el) => (inputRefs.current[i] = el)}
                type="text"
                inputMode="numeric"
                maxLength={1}
                value={digit}
                onChange={(e) => handleChange(i, e.target.value)}
                onKeyDown={(e) => handleKeyDown(i, e)}
                className={`otp-box ${digit ? "otp-filled" : ""}`}
              />
            ))}
          </div>

          <button type="submit" className="auth-btn" disabled={loading || otp.join("").length !== 6}>
            {loading ? <span className="spinner" /> : "Verify Code"}
          </button>
        </form>

        <div className="otp-resend">
          {resendTimer > 0 ? (
            <p>Resend code in <span>{resendTimer}s</span></p>
          ) : (
            <button onClick={handleResend} disabled={resending} className="resend-btn">
              {resending ? "Sending..." : "Resend OTP"}
            </button>
          )}
        </div>

        <p className="auth-link">
          <span
            style={{ cursor: "pointer", color: "#4f6ef7" }}
            onClick={() => navigate("/login")}
          >
            ← Back to login
          </span>
        </p>
      </div>
    </div>
  );
}
